import os
import io
import csv
import json
import hashlib
import tensorflow as tf
import numpy as np
import pandas as pd
from flask import Flask, request, jsonify
from tensorflow import keras
from tensorflow.keras import layers
from werkzeug.utils import secure_filename
from datetime import datetime
import base64
from PIL import Image

app = Flask(__name__)

UPLOAD_FOLDER = 'uploads'
MODEL_FOLDER = 'models'
TRAINING_DATA_FOLDER = 'training_data'
ALLOWED_EXTENSIONS = {'csv', 'png', 'jpg', 'jpeg'}

os.makedirs(UPLOAD_FOLDER, exist_ok=True)
os.makedirs(MODEL_FOLDER, exist_ok=True)
os.makedirs(TRAINING_DATA_FOLDER, exist_ok=True)

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = 100 * 1024 * 1024

class ModelManager:
    def __init__(self):
        self.model = None
        self.training_data = []
        self.labels = []
        self.num_classes = 10
        self.image_size = (128, 128)
        self.model_path = os.path.join(MODEL_FOLDER, 'current_model.h5')
        self.load_or_create_model()
        
    def load_or_create_model(self):
        if os.path.exists(self.model_path):
            self.model = keras.models.load_model(self.model_path)
        else:
            self.create_model()
    
    def create_model(self):
        self.model = keras.Sequential([
            layers.Input(shape=(*self.image_size, 3)),
            layers.Conv2D(32, 3, activation='relu'),
            layers.MaxPooling2D(),
            layers.Conv2D(64, 3, activation='relu'),
            layers.MaxPooling2D(),
            layers.Conv2D(128, 3, activation='relu'),
            layers.MaxPooling2D(),
            layers.Flatten(),
            layers.Dense(256, activation='relu'),
            layers.Dropout(0.5),
            layers.Dense(self.num_classes, activation='softmax')
        ])
        
        self.model.compile(
            optimizer='adam',
            loss='sparse_categorical_crossentropy',
            metrics=['accuracy']
        )
        
    def save_model(self):
        self.model.save(self.model_path)
        
    def train(self, images, labels, epochs=10, batch_size=32):
        images = np.array(images)
        labels = np.array(labels)
        
        history = self.model.fit(
            images, labels,
            epochs=epochs,
            batch_size=batch_size,
            validation_split=0.2,
            verbose=1
        )
        
        self.save_model()
        return history.history
        
    def predict(self, image):
        image = np.expand_dims(image, axis=0)
        predictions = self.model.predict(image)
        return predictions[0]

model_manager = ModelManager()

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def process_image(image_data, is_base64=False):
    if is_base64:
        image_bytes = base64.b64decode(image_data)
        image = Image.open(io.BytesIO(image_bytes))
    else:
        image = Image.open(image_data)
    
    image = image.convert('RGB')
    image = image.resize(model_manager.image_size)
    image_array = np.array(image) / 255.0
    return image_array

def save_training_example(image_array, label):
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    filename = f'training_{timestamp}_{label}.npy'
    filepath = os.path.join(TRAINING_DATA_FOLDER, filename)
    np.save(filepath, image_array)
    
    metadata_file = os.path.join(TRAINING_DATA_FOLDER, 'metadata.csv')
    with open(metadata_file, 'a', newline='') as f:
        writer = csv.writer(f)
        writer.writerow([filename, label, timestamp])
    
    return filepath

@app.route('/api/upload_csv', methods=['POST'])
def upload_csv():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if not allowed_file(file.filename):
        return jsonify({'error': 'Invalid file type'}), 400
    
    filename = secure_filename(file.filename)
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    file.save(filepath)
    
    try:
        df = pd.read_csv(filepath)
        
        if 'image_path' in df.columns and 'label' in df.columns:
            images = []
            labels = []
            
            for _, row in df.iterrows():
                img_path = row['image_path']
                if os.path.exists(img_path):
                    image = process_image(img_path)
                    images.append(image)
                    labels.append(int(row['label']))
            
            return jsonify({
                'message': 'CSV uploaded successfully',
                'rows': len(df),
                'valid_images': len(images),
                'filepath': filepath
            }), 200
        
        elif 'image_base64' in df.columns and 'label' in df.columns:
            images = []
            labels = []
            
            for _, row in df.iterrows():
                try:
                    image = process_image(row['image_base64'], is_base64=True)
                    images.append(image)
                    labels.append(int(row['label']))
                except Exception as e:
                    continue
            
            return jsonify({
                'message': 'CSV uploaded successfully',
                'rows': len(df),
                'valid_images': len(images),
                'filepath': filepath
            }), 200
        
        else:
            return jsonify({
                'message': 'CSV uploaded successfully',
                'rows': len(df),
                'columns': list(df.columns),
                'filepath': filepath
            }), 200
            
    except Exception as e:
        return jsonify({'error': f'Error processing CSV: {str(e)}'}), 500

@app.route('/api/contribute', methods=['POST'])
def contribute_example():
    try:
        if 'image' not in request.files and 'image_base64' not in request.form:
            return jsonify({'error': 'No image provided'}), 400
        
        if 'label' not in request.form:
            return jsonify({'error': 'No label provided'}), 400
        
        label = int(request.form['label'])
        
        if label < 0 or label >= model_manager.num_classes:
            return jsonify({'error': f'Label must be between 0 and {model_manager.num_classes-1}'}), 400
        
        if 'image' in request.files:
            image_file = request.files['image']
            image_array = process_image(image_file)
        else:
            image_base64 = request.form['image_base64']
            image_array = process_image(image_base64, is_base64=True)
        
        filepath = save_training_example(image_array, label)
        
        return jsonify({
            'message': 'Training example contributed successfully',
            'label': label,
            'filepath': filepath
        }), 200
        
    except Exception as e:
        return jsonify({'error': f'Error processing contribution: {str(e)}'}), 500

@app.route('/api/contribute_batch', methods=['POST'])
def contribute_batch():
    try:
        data = request.get_json()
        
        if 'examples' not in data:
            return jsonify({'error': 'No examples provided'}), 400
        
        examples = data['examples']
        saved_count = 0
        
        for example in examples:
            if 'image_base64' not in example or 'label' not in example:
                continue
            
            try:
                label = int(example['label'])
                if label < 0 or label >= model_manager.num_classes:
                    continue
                
                image_array = process_image(example['image_base64'], is_base64=True)
                save_training_example(image_array, label)
                saved_count += 1
            except:
                continue
        
        return jsonify({
            'message': 'Batch contribution processed',
            'total_examples': len(examples),
            'saved_examples': saved_count
        }), 200
        
    except Exception as e:
        return jsonify({'error': f'Error processing batch: {str(e)}'}), 500

@app.route('/api/train', methods=['POST'])
def train_model():
    try:
        data = request.get_json() or {}
        epochs = int(data.get('epochs', 10))
        batch_size = int(data.get('batch_size', 32))
        
        metadata_file = os.path.join(TRAINING_DATA_FOLDER, 'metadata.csv')
        
        if not os.path.exists(metadata_file):
            return jsonify({'error': 'No training data available'}), 400
        
        images = []
        labels = []
        
        with open(metadata_file, 'r') as f:
            reader = csv.reader(f)
            for row in reader:
                if len(row) >= 2:
                    filename, label = row[0], row[1]
                    filepath = os.path.join(TRAINING_DATA_FOLDER, filename)
                    
                    if os.path.exists(filepath):
                        image_array = np.load(filepath)
                        images.append(image_array)
                        labels.append(int(label))
        
        if len(images) == 0:
            return jsonify({'error': 'No valid training data found'}), 400
        
        history = model_manager.train(images, labels, epochs=epochs, batch_size=batch_size)
        
        return jsonify({
            'message': 'Model trained successfully',
            'training_samples': len(images),
            'epochs': epochs,
            'history': {
                'accuracy': [float(x) for x in history['accuracy']],
                'loss': [float(x) for x in history['loss']],
                'val_accuracy': [float(x) for x in history.get('val_accuracy', [])],
                'val_loss': [float(x) for x in history.get('val_loss', [])]
            }
        }), 200
        
    except Exception as e:
        return jsonify({'error': f'Error training model: {str(e)}'}), 500

@app.route('/api/train_from_csv', methods=['POST'])
def train_from_csv():
    try:
        if 'file' not in request.files:
            return jsonify({'error': 'No file provided'}), 400
        
        file = request.files['file']
        
        if not allowed_file(file.filename):
            return jsonify({'error': 'Invalid file type'}), 400
        
        data = request.form
        epochs = int(data.get('epochs', 10))
        batch_size = int(data.get('batch_size', 32))
        
        df = pd.read_csv(file)
        
        images = []
        labels = []
        
        if 'image_base64' in df.columns and 'label' in df.columns:
            for _, row in df.iterrows():
                try:
                    image = process_image(row['image_base64'], is_base64=True)
                    label = int(row['label'])
                    
                    if 0 <= label < model_manager.num_classes:
                        images.append(image)
                        labels.append(label)
                        save_training_example(image, label)
                except:
                    continue
        
        elif 'image_path' in df.columns and 'label' in df.columns:
            for _, row in df.iterrows():
                try:
                    img_path = row['image_path']
                    if os.path.exists(img_path):
                        image = process_image(img_path)
                        label = int(row['label'])
                        
                        if 0 <= label < model_manager.num_classes:
                            images.append(image)
                            labels.append(label)
                            save_training_example(image, label)
                except:
                    continue
        
        if len(images) == 0:
            return jsonify({'error': 'No valid training data in CSV'}), 400
        
        history = model_manager.train(images, labels, epochs=epochs, batch_size=batch_size)
        
        return jsonify({
            'message': 'Model trained from CSV successfully',
            'training_samples': len(images),
            'epochs': epochs,
            'history': {
                'accuracy': [float(x) for x in history['accuracy']],
                'loss': [float(x) for x in history['loss']],
                'val_accuracy': [float(x) for x in history.get('val_accuracy', [])],
                'val_loss': [float(x) for x in history.get('val_loss', [])]
            }
        }), 200
        
    except Exception as e:
        return jsonify({'error': f'Error training from CSV: {str(e)}'}), 500

@app.route('/api/predict', methods=['POST'])
def predict():
    try:
        if 'image' not in request.files and 'image_base64' not in request.form:
            return jsonify({'error': 'No image provided'}), 400
        
        if 'image' in request.files:
            image_file = request.files['image']
            image_array = process_image(image_file)
        else:
            image_base64 = request.form['image_base64']
            image_array = process_image(image_base64, is_base64=True)
        
        predictions = model_manager.predict(image_array)
        
        predicted_class = int(np.argmax(predictions))
        confidence = float(predictions[predicted_class])
        
        return jsonify({
            'predicted_class': predicted_class,
            'confidence': confidence,
            'all_predictions': {str(i): float(p) for i, p in enumerate(predictions)}
        }), 200
        
    except Exception as e:
        return jsonify({'error': f'Error making prediction: {str(e)}'}), 500

@app.route('/api/model_info', methods=['GET'])
def model_info():
    try:
        metadata_file = os.path.join(TRAINING_DATA_FOLDER, 'metadata.csv')
        training_samples = 0
        
        if os.path.exists(metadata_file):
            with open(metadata_file, 'r') as f:
                training_samples = sum(1 for _ in csv.reader(f))
        
        return jsonify({
            'num_classes': model_manager.num_classes,
            'image_size': model_manager.image_size,
            'training_samples': training_samples,
            'model_exists': os.path.exists(model_manager.model_path)
        }), 200
        
    except Exception as e:
        return jsonify({'error': f'Error getting model info: {str(e)}'}), 500

@app.route('/api/health', methods=['GET'])
def health_check():
    return jsonify({'status': 'healthy', 'model_loaded': model_manager.model is not None}), 200

